                    }
                    if (entry.time.isNotBlank()) {
                        InfoChip(Icons.Default.Schedule, entry.time, accent)
                    }
                    if (entry.location.isNotBlank()) {
                        InfoChip(Icons.Default.LocationOn, entry.location, accent)
                    }
