// ── Bus map card ──────────────────────────────────────────────────────────────
@SuppressLint("MissingPermission")
@Composable
private fun BusMapCard(trips: List<SavedBusTrip>, hasLocationPermission: Boolean) {
    val context = LocalContext.current

    // Collect visible stop markers (deduplicated by stop name)
    val stopMarkers = remember(trips) {
        trips
            .map { it.stopName }
            .distinct()
            .mapNotNull { name -> knownStopCoordinates[name]?.let { name to it } }
    }

    val cameraPositionState = rememberCameraPositionState {
        position = CameraPosition.fromLatLngZoom(uiucCampusCenter, 14f)
    }

    // Move camera to user's last known location once we have permission
    LaunchedEffect(hasLocationPermission) {
        if (hasLocationPermission) {
            val client = LocationServices.getFusedLocationProviderClient(context)
            client.lastLocation.addOnSuccessListener { loc ->
                if (loc != null) {
                    cameraPositionState.move(
                        CameraUpdateFactory.newLatLngZoom(
                            LatLng(loc.latitude, loc.longitude), 14f
                        )
                    )
                }
            }
        }
    }

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 16.dp, vertical = 8.dp),
        shape = RoundedCornerShape(16.dp),
        elevation = CardDefaults.cardElevation(4.dp)
    ) {
        Box(modifier = Modifier.height(220.dp)) {
            GoogleMap(
                modifier = Modifier.fillMaxSize(),
                cameraPositionState = cameraPositionState,
                properties = MapProperties(isMyLocationEnabled = hasLocationPermission),
                uiSettings = MapUiSettings(
                    myLocationButtonEnabled = hasLocationPermission,
                    zoomControlsEnabled = false,
                    mapToolbarEnabled = false
                )
            ) {
                stopMarkers.forEach { (name, latLng) ->
                    Marker(
                        state = MarkerState(position = latLng),
                        title = name,
                        icon = BitmapDescriptorFactory.defaultMarker(
                            BitmapDescriptorFactory.HUE_ORANGE
                        )
                    )
                }
            }

            // Label overlay
            Surface(
                modifier = Modifier
                    .align(Alignment.TopStart)
                    .padding(8.dp),
                shape = RoundedCornerShape(8.dp),
                color = busAccent
            ) {
                Text(
                    "Bus Stops",
                    style = MaterialTheme.typography.labelSmall,
                    color = Color.White,
                    fontWeight = FontWeight.SemiBold,
                    modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)
                )
            }
        }
    }
}

