@SuppressLint("MissingPermission", "SetJavaScriptEnabled")
@Composable
private fun BusMapCard(trips: List<SavedBusTrip>, hasLocationPermission: Boolean) {
    val context = LocalContext.current

    var userLat by remember { mutableStateOf<Double?>(null) }
    var userLng by remember { mutableStateOf<Double?>(null) }

    LaunchedEffect(hasLocationPermission) {
        if (hasLocationPermission) {
            LocationServices.getFusedLocationProviderClient(context)
                .lastLocation
                .addOnSuccessListener { loc ->
                    if (loc != null) { userLat = loc.latitude; userLng = loc.longitude }
                }
        }
    }

    val stopMarkers = remember(trips) {
        trips.map { it.stopName }.distinct()
            .mapNotNull { name -> knownStopCoordinates[name]?.let { name to it } }
    }

    val centerLat = userLat ?: uiucCampusCenter.first
    val centerLng = userLng ?: uiucCampusCenter.second
    val html = remember(centerLat, centerLng, stopMarkers) {
        buildLeafletHtml(centerLat, centerLng, userLat, userLng, stopMarkers)
    }

    var lastHtml by remember { mutableStateOf("") }

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 16.dp, vertical = 8.dp),
        shape = RoundedCornerShape(16.dp),
        elevation = CardDefaults.cardElevation(4.dp)
    ) {
        Box(modifier = Modifier.height(220.dp)) {
            AndroidView(
                factory = { ctx ->
                    WebView(ctx).apply {
                        settings.javaScriptEnabled = true
                        settings.domStorageEnabled = true
                        webViewClient = WebViewClient()
                        loadDataWithBaseURL(
                            "https://openstreetmap.org", html, "text/html", "UTF-8", null
                        )
                        lastHtml = html
                    }
                },
                update = { wv ->
                    if (html != lastHtml) {
                        lastHtml = html
                        wv.loadDataWithBaseURL(
                            "https://openstreetmap.org", html, "text/html", "UTF-8", null
                        )
                    }
                },
                modifier = Modifier.fillMaxSize()
            )

            Surface(
                modifier = Modifier
                    .align(Alignment.TopStart)
                    .padding(8.dp),
                shape = RoundedCornerShape(8.dp),
                color = busAccent
            ) {
                Text(
                    "Bus Stops · OpenStreetMap",
                    style = MaterialTheme.typography.labelSmall,
                    color = Color.White,
                    fontWeight = FontWeight.SemiBold,
                    modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)
                )
            }
        }
    }
}

private fun buildLeafletHtml(
    centerLat: Double,
    centerLng: Double,
    userLat: Double?,
    userLng: Double?,
    stops: List<Pair<String, Pair<Double, Double>>>
): String {
    val userMarkerJs = if (userLat != null && userLng != null) {
        """L.circleMarker([$userLat, $userLng], {
            radius: 9, fillColor: '#4285F4', color: '#fff',
            weight: 2.5, fillOpacity: 1
          }).addTo(map).bindPopup('<b>You are here</b>');"""
    } else ""

    val stopMarkersJs = stops.joinToString("\n") { (name, coord) ->
        val safeN = name.replace("'", "\\'")
        """L.circleMarker([${coord.first}, ${coord.second}], {
            radius: 10, fillColor: '#E65100', color: '#fff',
            weight: 2, fillOpacity: 0.9
          }).addTo(map).bindPopup('<b>$safeN</b>');"""
    }

    return """<!DOCTYPE html>
<html>
<head>
  <meta name="viewport" content="width=device-width,initial-scale=1,maximum-scale=1">
  <link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css"/>
  <script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script>
  <style>* {margin:0;padding:0;} #map {width:100vw;height:100vh;}</style>
</head>
<body>
<div id="map"></div>
<script>
  var map = L.map('map', {zoomControl:false, attributionControl:false})
             .setView([$centerLat, $centerLng], 15);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(map);
  $userMarkerJs
  $stopMarkersJs
</script>
</body>
</html>"""
}

